int cmpi462(const void* a,const void* b){ return *(int*)a-*(int*)b; }
int minMoves2(int* nums, int n){
    qsort(nums,n,sizeof(int),cmpi462);
    int m=nums[n/2], ans=0;
    for(int i=0;i<n;i++){ int d=nums[i]-m; ans+=d<0?-d:d; }
    return ans;
}
